/// </summary>
[BusinessEvents(classStr(ETGVendPaymPostedBusinessEventContract),
    'ETG vendor payment journal event',
    'This business event will send vendor payment journal details', 
    ModuleAxapta::AccountsPayable)]
public final class ETGVendPaymPostedBusinessEvent extends BusinessEventsBase
{
    private ETGCustPaymIntegrationHistory custPaymIntegrationHistory;
}

