private ETGCustPaymIntegrationHistory parmCustPaymIntegrationHistory(ETGCustPaymIntegrationHistory _custPaymIntegrationHistory = custPaymIntegrationHistory)
{
    custPaymIntegrationHistory = _custPaymIntegrationHistory;

    return custPaymIntegrationHistory;
}

/// <summary>
/// Creates a <c>ETGVendPaymPostedBusinessEvent</c> from a <c>ETGCustPaymIntegrationHistory</c> record.
/// </summary>
/// <param name = "_custPaymIntegrationHistory"> A <c>ETGCustPaymIntegrationHistory</c> record.</param>
/// <returns>A <c>ETGVendPaymPostedBusinessEvent</c>.</returns>
public static ETGVendPaymPostedBusinessEvent newFromCustPaymIntegrationHistory(ETGCustPaymIntegrationHistory _custPaymIntegrationHistory)
{
    var businessEvent =  new ETGVendPaymPostedBusinessEvent();
    businessEvent.parmCustPaymIntegrationHistory(_custPaymIntegrationHistory);
    return businessEvent;
}
